Author one complete WGSL compute shader from the supplied contract.
Return only the complete WGSL source; no Markdown fence, diff, or explanation.
The shader must implement every binding, entry-point, dispatch, bounds, and arithmetic requirement exactly.
<task_id>writer-v2-calibration-distance-pair-001</task_id>
<specification>
The shader operates on one logical f32 element per global x invocation. It must compute the absolute difference between the corresponding left and right input values, store the result in output_values[params.output_offset + index], and guard all reads and writes with the declared logical length.
</specification>
<interface_contract>
{
  "entryPoint": "main",
  "stage": "compute",
  "requiredOverrides": [
    {
      "name": "WORKGROUP_SIZE",
      "type": "u32",
      "default": 256
    }
  ],
  "bindings": [
    {
      "group": 0,
      "binding": 0,
      "name": "left_values",
      "kind": "read_only_storage",
      "wgslType": "array<f32>"
    },
    {
      "group": 0,
      "binding": 1,
      "name": "right_values",
      "kind": "read_only_storage",
      "wgslType": "array<f32>"
    },
    {
      "group": 0,
      "binding": 2,
      "name": "output_values",
      "kind": "read_write_storage",
      "wgslType": "array<f32>"
    },
    {
      "group": 0,
      "binding": 3,
      "name": "params",
      "kind": "uniform",
      "wgslType": "Params"
    }
  ],
  "uniformLayout": [
    {
      "name": "length",
      "type": "u32",
      "byteOffset": 0
    },
    {
      "name": "output_offset",
      "type": "u32",
      "byteOffset": 4
    },
    {
      "name": "first_reserved",
      "type": "f32",
      "byteOffset": 8
    },
    {
      "name": "second_reserved",
      "type": "f32",
      "byteOffset": 12
    }
  ],
  "dispatch": "ceil(params.length / WORKGROUP_SIZE) workgroups in x; y=1; z=1",
  "requiredBuiltin": "global_invocation_id",
  "boundsRule": "Return when global_invocation_id.x >= params.length.",
  "outputRule": "Write only output_values[params.output_offset + index]."
}
</interface_contract>

